"use client";

import Image from "next/image";
import router from "next/router";
import { useState } from "react";


export default function Hero() {


    const imagePairs = [
        { normal: "/hero/51.png", hover: "/hero/52.png" },
        { normal: "/hero/21.png", hover: "/hero/22.png" },
        { normal: "/hero/12.png", hover: "/hero/11.png" },
        { normal: "/hero/41.png", hover: "/hero/42.png" },
        { normal: "/hero/31.png", hover: "/hero/32.png", link: "/chang" },
    ];

    return (
        <div className="h-[100vh] w-full">
            <div className="grid grid-cols-5 h-full">
                {imagePairs.map((pair, index) => (
                    <div
                        key={index}
                        className="bg-gray-500 border-r border-white relative group cursor-pointer"
                        onClick={() => {
                            if (pair.link) {
                                router.push(pair.link);
                            }
                        }}
                    >
                        <Image
                            src={pair.normal}
                            alt="Hero"
                            width={400}
                            height={1000}
                            className="w-full h-full object-cover"
                        />
                        {/* 개별 이미지에 필터 적용 */}
                        <div className="absolute inset-0 bg-gray-500/10 group-hover:bg-gray-500/5 transition-colors duration-300"></div>
                    </div>
                ))}
            </div>
        </div>
    )
}